package core.org.apache.calcite.util.mapping;

public abstract class AbstractSourceMapping extends Mappings . AbstractMapping implements Mapping { private final int sourceCount ; private final int targetCount ; public AbstractSourceMapping ( int sourceCount , int targetCount ) { this . sourceCount = sourceCount ; this . targetCount = targetCount ; } @ Override public int getSourceCount ( ) { return sourceCount ; } @ Override public int getTargetCount ( ) { return targetCount ; } public Mapping inverse ( ) { return Mappings . invert ( this ) ; } public int size ( ) { return targetCount ; } public void clear ( ) { throw new UnsupportedOperationException ( ) ; } public MappingType getMappingType ( ) { return MappingType . INVERSE_PARTIAL_FUNCTION ; } public Iterator < IntPair > iterator ( ) { return new Iterator < IntPair > ( ) { int source ; int target = - 1 ; { moveToNext ( ) ; } private void moveToNext ( ) { while ( ++ target < targetCount ) { source = getSourceOpt ( target ) ; if ( source >= 0 ) { break ; } } } public boolean hasNext ( ) { return target < targetCount ; } public IntPair next ( ) { IntPair p = new IntPair ( source , target ) ; moveToNext ( ) ; return p ; } public void remove ( ) { throw new UnsupportedOperationException ( "remove" ) ; } } ; } public abstract int getSourceOpt ( int source ) ; }